import React from 'react';
import { observer, inject } from 'mobx-react';
import { errBoundary } from '@/components/ErrorBoundary';
import BackBtn from '@/components/BackBtn';
import { EditTableRow, EditTableCell } from '@/components/EditTable';
import { Table, Radio, Select } from 'antd';
import HomeStore, {
    IWordItem
} from '@/store/Home/typing';
import { TARGET_TYPE_LIST } from './constant';
import { getLocal, setLocal } from '@/utils/method';
import {} from '@/utils/constant';
import styles from './index.less';

interface IProps {
    homeStore: HomeStore;
}

interface IState {
    wordList: IWordItem
}

@inject('homeStore')
@observer
class Index extends React.Component<IProps, IState> {
    constructor(props: IProps) {
        super(props);
        this.state = {
            wordList: []
        };
    }
    componentDidMount() {
        const _this = this;
        _this.initData();
    }
    componentWillUnmount() {
        
    }
    initData = async () => {
        let wordList = getLocal('wordList');
        wordList && (wordList = JSON.parse(wordList));
        if (!wordList || wordList.length < 1) {
            const { data, ifSuccess } = await this.props.homeStore.getWordList();
            if (ifSuccess) {
                const result = data.result;
                setLocal('wordList', JSON.stringify(result));
                this.setState({
                    wordList: result
                });
            } else {
                wordList && wordList.length > 0 && this.setState({ wordList });
            }
        } else {
            wordList && wordList.length > 0 && this.setState({ wordList });
        }
    };

    render() {
        const _this = this;
        const { wordList } = _this.state;
        const columns = [
            {
                title: '关键字',
                dataIndex: 'keyword',
                width: 200,
                fixed: 'left',
                key: 'keyword'
            },
            {
                title: '热度',
                dataIndex: 'wholeHot',
                defaultSortOrder: 'descend',
                sorter: (a, b) => a.wholeHot - b.wholeHot,
            },
            {
                title: '竞品数量',
                dataIndex: 'competition',
                sorter: (a, b) => a.competition - b.competition,
            },
            {
                title: '个均热度',
                dataIndex: 'hotAve',
                sorter: (a, b) => (a.wholeHot / (a.competition || 1)) - (b.wholeHot / (b.competition || 1)),
                render: (text, row) => (row.wholeHot / (row.competition || 1)).toFixed(2)
            },
            {
                title: '点击率',
                dataIndex: 'marketAvgCtr',
                sorter: (a, b) => a.marketAvgCtr - b.marketAvgCtr,
                render: text => (text * 100).toFixed(2) + '%',
            },
            {
                title: '点击均价',
                dataIndex: 'recPrice',
                sorter: (a, b) => a.recPrice - b.recPrice,
                render: text => (text / 100).toFixed(2)
            }
        ];
        const components = {
            body: {
                row: EditTableRow,
                cell: EditTableCell
            }
        };

        return (
            <div id="page-homepage">
                <Table
                    rowKey="f_province_id"
                    loading={false}
                    components={components}
                    columns={columns}
                    scroll={{ y: 550 }}
                    dataSource={wordList}
                    pagination={false}
                    locale={{
                        emptyText: '暂无结果'
                    }}
                />
            </div>
        );
    }
}

export default errBoundary(Index);
